        // +0 exponent results to NaN
        var c = 42 ** -0;
        // -0 exponent results to NaN
        var d = NaN ** 1;
        // NaN with non-zero exponent is NaN
        var e = 2 ** Infinity;
        // abs(base) > 1 with Infinity as exponent is Infinity
        var f = 2 ** -Infinity;
        // abs(base) > 1 with -Infinity as exponent is +0
        var g = (-7) ** (0.5);
        var h = 2324334 ** 34343443;
        var i = (-2324334) ** 34343443;
        var j = 2 ** (-3);
        var k = 2.0 ** -3;
        var l = 2.0 ** (5 - 7);
        var m = 3 ** -10;  // Result will be 0.000016935087808430286, which is too long""".stripMargin.trim,
      expected = """var a = NaN;
        var b = 1;
        var c = 1;
        var d = NaN;
        var e = 1/0;
        var f = 0;
        var g = NaN;
        var h = 1/0;
        var i = -1/0;
        var j = .125;
